import http from "../01_axios"
import {
  apiGetAdvertisingPosition,
  apiMakeAdvertisingContract,
  apiGetAllAdvertisingPosition,
  apiGetAdvertisingPositionDetail,
  apiAddAdvertisingPosition,
  apiUpdateAdvertisingPosition,
  apiActiveAdvertisingPosition,
  apiDeactiveAdvertisingPosition,
  apiGetAdvertisingContractForm,
} from "./urls"

const getAdvertisingContractForm = body =>
  http.post(apiGetAdvertisingContractForm, body)

const getListAdvertisingPosition = params =>
  http.get(apiGetAdvertisingPosition, { params })

const makeAdvertisingContract = body =>
  http.post(apiMakeAdvertisingContract, body)

const getAllAdvertisingPosition = params =>
  http.get(apiGetAllAdvertisingPosition, { params })

const getAdvertisingPositionDetail = params =>
  http.get(apiGetAdvertisingPositionDetail, { params })

const addAdvertisingPosition = body =>
  http.post(apiAddAdvertisingPosition, body)

const updateAdvertisingPosition = body =>
  http.patch(apiUpdateAdvertisingPosition, body)

const activeAdvertisingPosition = params =>
  http.patch(apiActiveAdvertisingPosition, null, { params })

const deactiveAdvertisingPosition = params =>
  http.patch(apiDeactiveAdvertisingPosition, null, { params })

const AdvertisementService = {
  getListAdvertisingPosition,
  makeAdvertisingContract,
  getAllAdvertisingPosition,
  getAdvertisingPositionDetail,
  addAdvertisingPosition,
  updateAdvertisingPosition,
  activeAdvertisingPosition,
  deactiveAdvertisingPosition,
  getAdvertisingContractForm,
}
export default AdvertisementService
